;(() => {
  const shell = document.getElementById('dot-field-shell');
  if (!shell) return;

  const canvas = document.createElement('canvas');
  canvas.setAttribute('aria-hidden', 'true');
  shell.appendChild(canvas);

  const ctx = canvas.getContext('2d', { alpha: true });
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  let raf = 0;
  let dots = [];
  let frame = 0;
  let size = { w: 0, h: 0, offsetX: 0, offsetY: 0 };
  const mouse = { x: -9999, y: -9999, prevX: -9999, prevY: -9999, speed: 0 };
  const glow = { opacity: 0 };
  let engagement = 0;

  function buildDots(w, h) {
    const step = 1.4 + 30;
    const cols = Math.max(1, Math.floor(w / step));
    const rows = Math.max(1, Math.floor(h / step));
    const padX = (w % step) / 2;
    const padY = (h % step) / 2;
    const next = [];

    for (let row = 0; row < rows; row++) {
      for (let col = 0; col < cols; col++) {
        const ax = padX + col * step + step / 2;
        const ay = padY + row * step + step / 2;
        next.push({ ax, ay, sx: ax, sy: ay, vx: 0, vy: 0 });
      }
    }

    dots = next;
  }

  function resize() {
    const rect = shell.getBoundingClientRect();
    size.w = rect.width;
    size.h = rect.height;
    size.offsetX = rect.left + window.scrollX;
    size.offsetY = rect.top + window.scrollY;
    canvas.width = Math.floor(size.w * dpr);
    canvas.height = Math.floor(size.h * dpr);
    canvas.style.width = size.w + 'px';
    canvas.style.height = size.h + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    buildDots(size.w, size.h);
  }

  function updateMouseSpeed() {
    const dx = mouse.prevX - mouse.x;
    const dy = mouse.prevY - mouse.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    mouse.speed += (dist - mouse.speed) * 0.5;
    if (mouse.speed < 0.001) mouse.speed = 0;
    mouse.prevX = mouse.x;
    mouse.prevY = mouse.y;
  }

  function tick() {
    frame += 1;
    updateMouseSpeed();
    const t = frame * 0.02;
    const targetEngagement = Math.min(mouse.speed / 5, 1);
    engagement += (targetEngagement - engagement) * 0.06;

    glow.opacity += (engagement - glow.opacity) * 0.08;
    ctx.clearRect(0, 0, size.w, size.h);

    const grad = ctx.createLinearGradient(0, 0, size.w, size.h);
    grad.addColorStop(0, 'rgba(168, 85, 247, 0.10)');
    grad.addColorStop(1, 'rgba(180, 151, 207, 0.08)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, size.w, size.h);

    const radius = 90 + mouse.speed * 1.2;
    const radiusSq = radius * radius;

    ctx.beginPath();
    for (let i = 0; i < dots.length; i++) {
      const dot = dots[i];
      const dx = mouse.x - dot.ax;
      const dy = mouse.y - dot.ay;
      const distSq = dx * dx + dy * dy;
      const dist = Math.sqrt(distSq) || 1;

      if (distSq < radiusSq && engagement > 0.01) {
        const tNorm = 1 - dist / radius;
        const push = tNorm * tNorm * 44 * engagement;
        const angle = Math.atan2(dy, dx);
        dot.sx += (dot.ax - Math.cos(angle) * push - dot.sx) * 0.15;
        dot.sy += (dot.ay - Math.sin(angle) * push - dot.sy) * 0.15;
      } else {
        dot.sx += (dot.ax - dot.sx) * 0.1;
        dot.sy += (dot.ay - dot.sy) * 0.1;
      }

      const waveX = Math.cos(dot.ay * 0.03 + t) * 0.8;
      const waveY = Math.sin(dot.ax * 0.03 + t * 0.7) * 0.8;
      const x = dot.sx + waveX;
      const y = dot.sy + waveY;
      const sparkleChance = ((i * 2654435761) ^ (frame >> 3)) >>> 0;
      const r = (sparkleChance % 100) < 3 ? 1.8 : 1.15;

      ctx.moveTo(x + r, y);
      ctx.arc(x, y, r, 0, Math.PI * 2);
    }
    ctx.fillStyle = 'rgba(221, 232, 255, 0.72)';
    ctx.fill();

    raf = window.requestAnimationFrame(tick);
  }

  window.addEventListener('mousemove', (event) => {
    mouse.x = event.clientX - size.offsetX;
    mouse.y = event.clientY - size.offsetY;
  }, { passive: true });

  window.addEventListener('resize', resize);
  resize();
  raf = window.requestAnimationFrame(tick);

  shell.addEventListener('mouseleave', () => {
    mouse.speed = 0;
  });

  window.addEventListener('beforeunload', () => {
    if (raf) window.cancelAnimationFrame(raf);
  });
})();

document.addEventListener('DOMContentLoaded',function(){
const sections=document.querySelectorAll('section[id]');
const navItems=document.querySelectorAll('.floating-nav .nav-item');
window.addEventListener('scroll',function(){
let current='';
sections.forEach(function(section){
const top=section.offsetTop-200;
const height=section.offsetHeight;
if(window.scrollY>=top&&window.scrollY<top+height){current=section.id;}
});
navItems.forEach(function(item){
item.classList.remove('active');
if(item.getAttribute('href')==='#'+current){item.classList.add('active');}
});
});
});
